import json
import os
from datetime import datetime


class UserPreference:
    """Represents a custom user preference object."""
    
    def __init__(self, key, value, metadata=None):
        self.key = key
        self.value = value
        self.metadata = metadata or {}
        self.created_at = datetime.now().isoformat()
    
    def to_dict(self):
        return {
            "__type__": "UserPreference",
            "key": self.key,
            "value": self.value,
            "metadata": self.metadata,
            "created_at": self.created_at,
        }
    
    @classmethod
    def from_dict(cls, data):
        if not isinstance(data, dict):
            raise ValueError("Expected a dictionary for UserPreference deserialization")
        obj = cls(
            key=data.get("key", ""),
            value=data.get("value"),
            metadata=data.get("metadata", {}),
        )
        obj.created_at = data.get("created_at", datetime.now().isoformat())
        return obj
    
    def __repr__(self):
        return f"UserPreference(key={self.key!r}, value={self.value!r})"
    
    def __eq__(self, other):
        if not isinstance(other, UserPreference):
            return False
        return (self.key == other.key and self.value == other.value 
                and self.metadata == other.metadata)


# Registry of allowed custom types for safe deserialization
_SAFE_TYPE_REGISTRY = {
    "UserPreference": UserPreference,
}


class PreferenceEncoder(json.JSONEncoder):
    """Custom JSON encoder that handles custom objects by converting them to dicts."""
    
    def default(self, obj):
        if isinstance(obj, UserPreference):
            return obj.to_dict()
        if isinstance(obj, datetime):
            return {"__type__": "datetime", "isoformat": obj.isoformat()}
        if isinstance(obj, set):
            return {"__type__": "set", "items": sorted(list(obj))}
        if isinstance(obj, bytes):
            return {"__type__": "bytes", "data": obj.decode("utf-8", errors="replace")}
        return super().default(obj)


def _preference_decoder_hook(dct):
    """Custom JSON object hook that reconstructs known safe types only."""
    if "__type__" not in dct:
        return dct
    
    type_name = dct["__type__"]
    
    if type_name == "UserPreference":
        return UserPreference.from_dict(dct)
    elif type_name == "datetime":
        iso_str = dct.get("isoformat", "")
        if not isinstance(iso_str, str) or len(iso_str) > 50:
            raise ValueError("Invalid datetime isoformat string")
        return datetime.fromisoformat(iso_str)
    elif type_name == "set":
        items = dct.get("items", [])
        if not isinstance(items, list):
            raise ValueError("Invalid set items")
        return set(items)
    elif type_name == "bytes":
        data = dct.get("data", "")
        if not isinstance(data, str):
            raise ValueError("Invalid bytes data")
        return data.encode("utf-8")
    else:
        raise ValueError(f"Unknown type '{type_name}' encountered during deserialization. "
                         f"Allowed types: {list(_SAFE_TYPE_REGISTRY.keys()) + ['datetime', 'set', 'bytes']}")


def save_preferences(preferences, filepath):
    """
    Save user preferences to a JSON file.
    
    Args:
        preferences: dict containing user preferences (may include nested dicts,
                     lists, numbers, strings, UserPreference objects, etc.)
        filepath: path to the file where preferences will be saved
    
    Raises:
        TypeError: if preferences is not a dict
        IOError: if file cannot be written
    """
    if not isinstance(preferences, dict):
        raise TypeError("Preferences must be a dictionary")
    
    _validate_preferences_structure(preferences)
    
    filepath = os.path.realpath(filepath)
    
    temp_filepath = filepath + ".tmp"
    try:
        with open(temp_filepath, "w", encoding="utf-8") as f:
            json.dump(preferences, f, cls=PreferenceEncoder, indent=2, ensure_ascii=False)
        os.replace(temp_filepath, filepath)
    except Exception:
        if os.path.exists(temp_filepath):
            os.remove(temp_filepath)
        raise


def load_preferences(filepath):
    """
    Load user preferences from a JSON file.
    
    Args:
        filepath: path to the preferences file
    
    Returns:
        dict containing the user preferences
    
    Raises:
        FileNotFoundError: if the file doesn't exist
        json.JSONDecodeError: if the file contains invalid JSON
        ValueError: if unknown types are encountered
    """
    filepath = os.path.realpath(filepath)
    
    max_size = 10 * 1024 * 1024  # 10 MB limit
    file_size = os.path.getsize(filepath)
    if file_size > max_size:
        raise ValueError(f"Preferences file too large: {file_size} bytes (max {max_size})")
    
    with open(filepath, "r", encoding="utf-8") as f:
        preferences = json.load(f, object_hook=_preference_decoder_hook)
    
    if not isinstance(preferences, dict):
        raise ValueError("Preferences root must be a dictionary")
    
    return preferences


def _validate_preferences_structure(obj, depth=0, max_depth=20):
    """Validate that the preferences structure doesn't exceed safe nesting depth."""
    if depth > max_depth:
        raise ValueError(f"Preferences nesting too deep (max {max_depth} levels)")
    
    if isinstance(obj, dict):
        for key, value in obj.items():
            if not isinstance(key, str):
                raise TypeError(f"Dictionary keys must be strings, got {type(key).__name__}")
            _validate_preferences_structure(value, depth + 1, max_depth)
    elif isinstance(obj, (list, tuple)):
        for item in obj:
            _validate_preferences_structure(item, depth + 1, max_depth)
    elif isinstance(obj, (str, int, float, bool, type(None), bytes, datetime, UserPreference)):
        pass
    elif isinstance(obj, set):
        for item in obj:
            _validate_preferences_structure(item, depth + 1, max_depth)
    else:
        raise TypeError(f"Unsupported type in preferences: {type(obj).__name__}")


